    <script>

        function GenerateSpisukLicaExcelExport() {

            var form = $(""#lice-filter-form"");

            $.ajax({
                type: ""GET"",
                url: '\GenerateSpisukLicaExcelExport',
                data: form.serialize(), // serializes the form's elements.
                success: function (data) {
                    console.log(data);
                    window.location.href = ""/Spravki/Home/DownloadReport/?fileName="" + data;
                }
            });
        }

        function clickGlobalSerchCheck() {

            var v = $("".form-check-input:checked"").val();
            if (v) {
                document.getElementById(""sections"").disabled = true;
            } else {
                document.getElementById(""sections"").disabled = false;
            }
            document.getElementById(""sections"").value = '';
            $("".selectpicker"").selectpicker('refresh');
        }
    </script>
